effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {

    float rad = angle * 0.0174533;
    mat2 rot = mat2(cos(rad),-sin(rad),sin(rad),cos(rad));
    mat2 invrot = mat2(cos(-rad),-sin(-rad),sin(-rad),cos(-rad));

    vec2 st = acScreenNorm;

    st -= acLayerCenterNorm;
    st.y *= (acScreenSize.y/acScreenSize.x);
    st *= rot;

    // Y Distance

    float distY = mod(st.y*amount,1.);

    if( distY < 0.5 ) {
        distY = -distY;
    } else {
        distY = 1.0-distY;
    }

    float absDistY = abs(distY);

    distY /= amount;

    // X Distance

    float xoffs = step(1.,mod(st.y*amount+0.5,2.)) * phase;

    float distX = mod(st.x*amount+xoffs,1.);

    if( distX < 0.5 ) {
        distX = -distX;
    } else {
        distX = 1.0-distX;
    }

    float absDistX = abs(distX);

    distX /= amount;

    // Sampling

    st.y += distY;
    st.x += distX;

    st *= invrot;
    st.y /= (acScreenSize.y/acScreenSize.x);
    st += acLayerCenterNorm;

    vec4 samp = texture2DCv(inputImg.texture,st);
    float lum = dot( samp.rgb, luminanceWeighting );

    float p = smoothstep( 0.4,0.6, lum + (1.-samp.a) + length(vec2(absDistX,absDistY)) + strength - 0.5);

    vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);

    //vec4 color1 = vec4(0., 0., 0., 1.);
    //vec4 color2 = vec4(1., 1., 1., 1.);

    vec4 outColor = mix( color1, color2, p ) * texColor.a;

    gl_FragColor = outColor;

}
